async def extract(
    input: ExtractInput | None = None,  # noqa: A002
    config: ExtractionConfig | None = None,
) -> ExtractionResult:
    """Extract content from a single bytes or URI input."""
    _rust_input = _to_rust_extract_input(input) if input is not None else _rust.ExtractInput()
    _rust_config = _to_rust_extraction_config(config) if config is not None else _rust.ExtractionConfig()
    return await _rust.extract(input=_rust_input, config=_rust_config)


async def extract_batch(
    inputs: list[ExtractInput],
    config: ExtractionConfig | None = None,
) -> ExtractionResult:
    """Extract content from multiple bytes or URI inputs."""
    _rust_inputs = [_to_rust_extract_input(__item) for __item in inputs]

    _rust_config = _to_rust_extraction_config(config) if config is not None else _rust.ExtractionConfig()
    return await _rust.extract_batch(inputs=_rust_inputs, config=_rust_config)


async def map_url(uri: str, config: UrlExtractionConfig | None = None) -> MapResult:
    """Discover all pages and sitemaps reachable from `uri` without extracting document content."""
    _rust_config = _to_rust_url_extraction_config(config) if config is not None else _rust.UrlExtractionConfig()
    return await _rust.map_url(uri=uri, config=_rust_config)


